effect.shader:
vec4 getSample( float a, float r ) {
    a *= 1. - (0.5/acLayerSize.x);
    a += 0.5/acLayerSize.x;
    vec2 sampleCoord = vec2(a,r);
    sampleCoord = (vec4(sampleCoord,0.0,1.0) * acLayerToScreen).xy;
    return texture2DCv(inputImg.texture,sampleCoord);
}

float smoothStep(float edge0, float edge1, float t) {
    if(edge0 == edge1) return 1.0;
    return smoothstep(edge0, edge1, t);
}

void main() {
    float rad = angle * 0.0174533;
    vec2 pos = acLayerNorm - 0.5;
    if(!stretch) {
        pos.x *= acLayerSize.x / acLayerSize.y;
    }
    pos /= scale;
    pos += (position*vec2(-1.0,1.0)) / 1000.0;
    float r = (length(pos)*2.0 - radius) / max(width,0.0000001);
    float a = mod(((atan(pos.y,pos.x)+rad)/6.28318)+0.5,1.0);
    a = mod(a * repeat,1.0);
    if(mirror) {
        a = abs(a * 2.0 - 1.0);
    }
    float cropFactor = (1.-(1./acLayerSize.x*(crop)));
    float featherFactor = (1.-(1./acLayerSize.x*(feather)));
    a = (a - 0.5) * featherFactor + 0.5;
    float featherDist = (1.0 - featherFactor);
    float f0 = smoothStep(0.0,featherDist,a);
    float f1 = smoothStep(1.0,1.0-featherDist,a);

    a = (a - 0.5) * cropFactor + 0.5;

    float cff = cropFactor * featherFactor;

    if( feather >= 0.0 && f0+f1 > 0.0 ) {
        gl_FragColor = mix( getSample(a+cff,r), mix( getSample(a-cff,r), getSample(a,r), f1 ), f0);
    } else {
        gl_FragColor = getSample(a,r);
    }

}
